function Counter() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(count + 1);
    console.log(count); // still 0 — the snapshot is frozen
  }

  return <button onClick={handleClick}>Count: {count}</button>;
}

function AlertButton() {
  const [message, setMessage] = useState('hello');

  function handleClick() {
    setTimeout(() => {
      // This alert captures the snapshot from when handleClick ran.
      // Even if the user changed message before 3 s elapsed,
      // this will still show the OLD value.
      alert(message);
    }, 3000);
  }

  return (
    <>
      <input value={message} onChange={e => setMessage(e.target.value)} />
      <button onClick={handleClick}>Alert in 3 s</button>
    </>
  );
}

function Form() {
  const [count, setCount] = useState(0);
  const [flag, setFlag] = useState(false);
  const [label, setLabel] = useState('idle');

  function handleSubmit() {
    setCount(c => c + 1); // queued
    setFlag(true);         // queued
    setLabel('done');      // queued
    // ↑ React batches all three and re-renders ONCE
  }

  console.log('render'); // called once per click, not three times
  return <button onClick={handleSubmit}>{label} ({count})</button>;
}

