  setUser(data.user);     // queued
  setLoading(false);      // queued
  // → one re-render (React 18+)
  // → two re-renders (React 17 and earlier)
}

import { flushSync } from 'react-dom';

function TodoList() {
  const [todos, setTodos] = useState([]);
  const listRef = useRef(null);

  function handleAdd() {
    flushSync(() => {
      setTodos(prev => [...prev, 'New item']);
    });
    // DOM has been updated synchronously — scroll works correctly
    listRef.current.lastChild.scrollIntoView();
  }

  return (
    <ul ref={listRef}>
      {todos.map((t, i) => <li key={i}>{t}</li>)}
    </ul>
  );
}

function BrokenCounter() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(count + 1); // queues: replace with 0+1 = 1
    setCount(count + 1); // queues: replace with 0+1 = 1 (same snapshot!)
    setCount(count + 1); // queues: replace with 0+1 = 1 (same snapshot!)
    // Result after render: count = 1, not 3
  }
  return <button onClick={handleClick}>+3? (broken): {count}</button>;
}

function WorkingCounter() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(c => c + 1); // queues: c => c+1
    setCount(c => c + 1); // queues: c => c+1 (applied to result of previous)
    setCount(c => c + 1); // queues: c => c+1 (applied to result of previous)
    // Result after render: count = 3
  }
  return <button onClick={handleClick}>+3 (correct): {count}</button>;
}

// Starting count: 0
setCount(5);        // queue: [5]         → pending = 5
setCount(c => c + 1); // queue: [5, c=>c+1] → pending = 6
setCount(42);       // queue: [5, c=>c+1, 42] → pending = 42
// Re-render with count = 42

function StaleExample() {
  const [count, setCount] = useState(0);
  const countRef = useRef(count);

  // Keep the ref in sync
  useEffect(() => {
    countRef.current = count;
  });

  function handleLongOp() {
    setTimeout(() => {
      // count is stale (snapshot from click time)
      console.log('snapshot count:', count);

      // countRef.current is always fresh
      console.log('ref count:', countRef.current);
    }, 3000);
  }

  return (
    <>
      <button onClick={() => setCount(c => c + 1)}>Increment</button>
      <button onClick={handleLongOp}>Log after 3s</button>
      <p>{count}</p>
    </>
  );
}

function Scoreboard() {
  const [score, setScore] = useState(0);

  function handleWin() {
    setScore(score + 10);
    // Wrong assumption: score is still 0 here, not 10
    if (score >= 100) {
      // This never runs in the same click that takes score from 90→100
      // because score is still the snapshot value (90), not the next value (100)
      alert('You win!');
    }
  }

  // Correct approach: check in the render or use derived state
  const hasWon = score >= 100;
  return (
    <>
      <button onClick={handleWin}>+10</button>
      {hasWon && <p>You win!</p>}
    </>
  );
}

function RenderCounter() {
  const [a, setA] = useState(0);
  const [b, setB] = useState(0);
  const renders = useRef(0);
  renders.current++;

  function handleBoth() {
    setA(x => x + 1);
    setB(x => x + 1);
    // Batched → 1 additional render
  }

  return (
    <div>
      <p>a: {a}, b: {b}</p>
      <p>Total renders: {renders.current}</p>
      <button onClick={handleBoth}>Update both</button>
    </div>
  );
}
// After 3 clicks: a=3, b=3, renders=4 (1 initial + 3 batched updates)

function TagManager() {
  const [tags, setTags] = useState(['react']);
  const [input, setInput] = useState('');

  function handleAdd() {
    // Both updates batched into one re-render
    setTags(prev => [...prev, input]); // new array, no mutation
    setInput('');                       // reset the input
  }

  return (
    <>
      <input value={input} onChange={e => setInput(e.target.value)} />
      <button onClick={handleAdd}>Add tag</button>
      <ul>{tags.map(t => <li key={t}>{t}</li>)}</ul>
    </>
  );
}

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('batches multiple state updates', async () => {
  const user = userEvent.setup();
  render(<WorkingCounter />);
  const btn = screen.getByRole('button', { name: /\+3/ });

  await user.click(btn);

  // After one click, count is 3 (three updaters chained)
  expect(btn).toHaveTextContent('+3 (correct): 3');
});

function Checkout() {
  const [items, setItems] = useState([]);
  const [status, setStatus] = useState('idle');
  const [error, setError] = useState(null);

  async function handleCheckout() {
    // Snapshot at call time: status='idle', error=null
    setStatus('loading');
    setError(null);
    // Both queued — one re-render with status='loading', error=null

    try {
      const result = await placeOrder(items);
      // New event (promise resolution) — React 18 batches these too
      setStatus('success');
      setItems([]);
    } catch (err) {
      setStatus('error');
      setError(err.message);
    }
  }

  return (
    <div>
      <p>Status: {status}</p>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <button onClick={handleCheckout} disabled={status === 'loading'}>
        {status === 'loading' ? 'Placing order…' : 'Checkout'}
      </button>
    </div>
  );
}

function Search() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (!query) return;
    let cancelled = false;

    fetchResults(query).then(data => {
      // Without the cancelled flag, a slow earlier request could
      // overwrite the results of a faster later one.
      if (!cancelled) setResults(data);
    });

    return () => { cancelled = true; };
  }, [query]);

  return (
    <>
      <input value={query} onChange={e => setQuery(e.target.value)} />
      <ul>{results.map(r => <li key={r.id}>{r.name}</li>)}</ul>
    </>
  );
}

import { useState, useTransition } from 'react';

function FilteredList({ items }) {
  const [filter, setFilter] = useState('');
  const [filtered, setFiltered] = useState(items);
  const [isPending, startTransition] = useTransition();

  function handleChange(e) {
    const value = e.target.value;
    setFilter(value); // urgent: keep input responsive

    startTransition(() => {
      // non-urgent: allow React to interrupt if a new keystroke arrives
      setFiltered(items.filter(i => i.includes(value)));
    });
  }

  return (
    <>
      <input value={filter} onChange={handleChange} />
      {isPending && <p>Filtering…</p>}
      <ul>{filtered.map(i => <li key={i}>{i}</li>)}</ul>
    </>
  );
}

// Multiple useState — update count & history together
function CounterA() {
  const [count, setCount] = useState(0);
  const [history, setHistory] = useState([]);

  function increment() {
    setCount(c => c + 1);
    setHistory(h => [...h, count + 1]); // risk: count is snapshot, not next value
  }
  // …
}

// useReducer — atomic update, no stale reads
function CounterB() {
  const [state, dispatch] = useReducer(
    (s, action) => {
      if (action === 'increment') {
        const next = s.count + 1;
        return { count: next, history: [...s.history, next] };
      }
      return s;
    },
    { count: 0, history: [] }
  );

  return (
    <button onClick={() => dispatch('increment')}>
      {state.count} (history: {state.history.join(', ')})
    </button>
  );
}
